const WRITE_ROLES=['SUPER_ADMIN','COMPANY_ADMIN','MANAGER','FINANCIER','MAGAZINIER','SHITES','ARKETAR'];
const MANAGER_ROLES=['SUPER_ADMIN','COMPANY_ADMIN','MANAGER','FINANCIER'];
const text=(v)=>String(v??'').trim();
const num=(v)=>Number(v||0);
function requestError(message,status=400){const e=new Error(message);e.status=status;return e;}
function dateOnly(v){return v instanceof Date?v.toISOString().slice(0,10):String(v||new Date().toISOString().slice(0,10)).slice(0,10);}
async function nextSequence(client,tenantId,companyId,key){const{rows}=await client.query(`INSERT INTO trace_lot_sequences(tenant_id,company_id,sequence_key,last_value) VALUES($1,$2,$3,1) ON CONFLICT(tenant_id,company_id,sequence_key) DO UPDATE SET last_value=trace_lot_sequences.last_value+1,updated_at=NOW() RETURNING last_value`,[tenantId,companyId,key]);return Number(rows[0].last_value);}
async function nextNo(client,tenantId,companyId,prefix,date,digits=6){const year=dateOnly(date).slice(0,4);const n=await nextSequence(client,tenantId,companyId,`${prefix}-${year}`);return`${prefix}-${year}-${String(n).padStart(digits,'0')}`;}
async function addChange(client,user,companyId,entityType,entityId,operation,metadata={}){await client.query(`INSERT INTO cloud_change_events(tenant_id,company_id,entity_type,entity_id,operation,metadata,user_id) VALUES($1,$2,$3,$4,$5,$6::jsonb,$7)`,[user.tenant_id,companyId,entityType,entityId,operation,JSON.stringify(metadata),user.id]);}

