const categorySchema=z.object({companyId:z.string().uuid(),code:z.string().trim().min(1).max(60),name:z.string().trim().min(2).max(160),parentId:z.string().uuid().nullable().optional(),defaultCostCenter:z.string().trim().max(120).optional().default(''),active:z.boolean().optional()});
