const routeSchema=z.object({companyId:z.string().uuid(),code:z.string().trim().min(1).max(70),name:z.string().trim().min(2).max(180),origin:z.string().trim().min(2).max(220),destination:z.string().trim().min(2).max(220),distanceKm:z.coerce.number().min(0),estimatedHours:z.coerce.number().min(0).default(0),borderPoint:z.string().trim().max(180).optional().default(''),tollCost:z.coerce.number().min(0).default(0),routeText:z.string().trim().max(3000).optional().default(''),active:z.boolean().optional()});
