const fuelSchema=z.object({companyId:z.string().uuid(),vehicleId:z.string().uuid(),tripId:z.string().uuid().nullable().optional(),supplierId:z.string().uuid().nullable().optional(),fuelDate:z.string().date(),fuelType:z.string().trim().max(40).optional().default(''),liters:z.coerce.number().positive(),pricePerLiter:z.coerce.number().min(0),odometerKm:z.coerce.number().min(0),stationName:z.string().trim().max(220).optional().default(''),externalDocumentNo:z.string().trim().max(120).optional().default(''),fullTank:z.boolean().default(false),paymentMethod:z.string().trim().max(30).optional().default('CASH'),paymentAccountType:z.string().trim().max(30).optional().default('CASH'),paymentReference:z.string().trim().max(160).optional().default(''),notes:z.string().trim().max(2000).optional().default('')});
const shiftSchema=z.object({companyId:z.string().uuid(),vehicleId:z.string().uuid(),driverUserId:z.string().uuid().nullable().optional(),tripId:z.string().uuid().nullable().optional(),driverName:z.string().trim().min(2).max(180),shiftStartAt:z.string().datetime({offset:true}),startOdometerKm:z.coerce.number().min(0).nullable().optional(),notes:z.string().trim().max(2000).optional().default('')});
const maintenanceItemSchema=z.object({itemType:z.enum(['PART','LABOR','SERVICE','OTHER']).default('PART'),description:z.string().trim().min(2).max(300),quantity:z.coerce.number().positive().default(1),unitPrice:z.coerce.number().min(0).default(0)});
const maintenanceSchema=z.object({companyId:z.string().uuid(),vehicleId:z.string().uuid(),supplierId:z.string().uuid().nullable().optional(),maintenanceType:z.string().trim().min(2).max(70),reportedAt:z.string().datetime({offset:true}).optional(),odometerKm:z.coerce.number().min(0).nullable().optional(),description:z.string().trim().min(2).max(3000),laborCost:z.coerce.number().min(0).default(0),partsCost:z.coerce.number().min(0).default(0),vatAmount:z.coerce.number().min(0).default(0),nextServiceDate:z.string().date().nullable().optional(),nextServiceOdometerKm:z.coerce.number().min(0).nullable().optional(),externalDocumentNo:z.string().trim().max(120).optional().default(''),notes:z.string().trim().max(2000).optional().default(''),items:z.array(maintenanceItemSchema).default([])});
